program test_f03_binding_exx_bccHe

   use mpi
   use librpa_f03
   implicit none

   integer, parameter :: nspins = 1
   integer, parameter :: nk1 = 2, nk2 = 2, nk3 = 2
   integer, parameter :: nkpts = nk1 * nk2 * nk3
   integer, parameter :: nstates = 8
   integer, parameter :: nbasis = nstates
   integer, parameter :: naux = 26
   integer, parameter :: natoms = 2
   real(dp), parameter :: pi = atan(1.0) * 4.0

   character(len=*), parameter :: prog = "test_f03_binding_exx_bccHe"
   character(len=200) :: info_str

   type(LibrpaHandler) :: h
   type(LibrpaOptions) :: opts

   integer :: ierr, myid, size
   real(dp) :: efermi
   real(dp) :: latt(3,3), recplatt(3,3), posi_cart(3, natoms), kpoints(3,nkpts)
   integer :: nbs_wfc(natoms), nbs_aux(natoms), types(natoms), map_ibzk(nkpts)
   integer :: i_kpoints_task(nkpts)

   real(dp), allocatable :: vexx(:,:,:)
   real(dp), allocatable :: wg(:,:,:), ekb(:,:,:)
   real(dp), allocatable :: ri_coeff(:,:,:,:)
   integer, allocatable :: atom_iR(:,:)
   complex(dp), allocatable :: wfc(:,:,:,:)
   complex(dp), allocatable :: vq(:,:,:), vq_cut(:,:,:)

   ! Counters
   integer :: n_k_points_task
   integer :: i_k_point, i_k_point_task, i_ap_cell, ia1, ia2, i_state, i_spin
   integer :: lbb_row, ubb_row
   integer :: lbb_col, ubb_col

   call initialize()

   call opts%init()

   call h%create(MPI_COMM_WORLD)
   call h%set_scf_dimension(nspins, nkpts, nstates, nbasis, 1, nstates, 1, nbasis)

   efermi = 0.00609624851934464917_dp
   call initialize_wg_ekb
   call h%set_wg_ekb_efermi(nspins, nkpts, nstates, wg, ekb, efermi)
   call finalize_wg_ekb

   call initialize_wfc
   i_k_point_task = 0
   do i_k_point = 1, nkpts
      if (mod(i_k_point - 1, size) == myid) then
         i_k_point_task = i_k_point_task + 1
         i_kpoints_task(i_k_point_task) = i_k_point
         call h%set_wfc(1, i_k_point, nstates, nbasis, wfc(:, :, i_k_point, 1))
      end if
   end do
   n_k_points_task = i_k_point_task
   write(*, *) "i_kpoints_task", i_kpoints_task(1:n_k_points_task)
   call finalize_wfc

   nbs_wfc(1) = 4
   nbs_wfc(2) = 4
   if (sum(nbs_wfc) /= nbasis) call finalize(.false.)
   call h%set_ao_basis_wfc(natoms, nbs_wfc)
   nbs_aux(1) = 13
   nbs_aux(2) = 13
   if (sum(nbs_aux) /= naux) call finalize(.false.)
   call h%set_ao_basis_aux(natoms, nbs_aux)

   latt(:,:) = 0.0_dp
   recplatt(:,:) = 0.0_dp
   latt(1, 1) = 5.66917838355132542_dp
   latt(2, 2) = 5.66917838355132542_dp
   latt(3, 3) = 5.66917838355132542_dp
   recplatt(1, 1) = 2.0_dp / latt(1, 1) * pi
   recplatt(2, 2) = 2.0_dp / latt(2, 2) * pi
   recplatt(3, 3) = 2.0_dp / latt(3, 3) * pi
   call h%set_latvec_and_G(latt, recplatt)
   !call librpa_test()

   types(1) = 0
   types(2) = 0
   posi_cart(:,:) = 0.0d0
   posi_cart(:,2) = 0.283458919177566271d1
   call h%set_atoms(natoms, types, posi_cart)

   !call mpi_barrier(MPI_COMM_WORLD, ierr)
   kpoints(:,:) = 0.0_dp
   kpoints(3,2) = sum(recplatt(3,:)) / 2.0_dp
   kpoints(2,3) = sum(recplatt(2,:)) / 2.0_dp
   kpoints(2,4) = sum(recplatt(2,:)) / 2.0_dp
   kpoints(3,4) = sum(recplatt(3,:)) / 2.0_dp
   kpoints(1,5:8) = sum(recplatt(1,:)) / 2.0_dp
   kpoints(3,6) = sum(recplatt(3,:)) / 2.0_dp
   kpoints(2,7) = sum(recplatt(2,:)) / 2.0_dp
   kpoints(2,8) = sum(recplatt(2,:)) / 2.0_dp
   kpoints(3,8) = sum(recplatt(3,:)) / 2.0_dp
   call h%set_kgrids_kvec(nk1, nk2, nk3, kpoints)

   call initialize_lri
   opts%parallel_routing = LIBRPA_ROUTING_LIBRI
   do i_ap_cell = 1, natoms*natoms*nkpts
      ia1 = atom_iR(1, i_ap_cell)
      ia2 = atom_iR(2, i_ap_cell)
      if (mod(i_ap_cell-1, size) /= myid) cycle
      call h%set_lri_coeff(opts%parallel_routing, ia1, ia2, &
                           nbs_wfc(ia1), nbs_wfc(ia2), nbs_aux(ia1), &
                           atom_iR(3:5, i_ap_cell), ri_coeff(:,:,:,i_ap_cell))
   end do
   call finalize_lri

   call initialize_coulomb
   lbb_row = 1
   ubb_row = naux
   lbb_col = 1
   ubb_col = naux
   do i_k_point = 1, nkpts
      if (mod(i_k_point - 1, size) == myid) then
         call h%set_aux_cut_coulomb_k_2d_block(i_k_point, &
            lbb_row, ubb_row, lbb_col, ubb_col, &
            vq_cut(lbb_row:ubb_row, lbb_col:ubb_col, i_k_point))
      end if
   end do
   call finalize_coulomb

   allocate(vexx(nstates, n_k_points_task, nspins))
   opts%use_kpara_scf_eigvec = .true.
   call h%build_exx(opts)
   call h%get_exx_pot_kgrid(opts, nspins, n_k_points_task, i_kpoints_task(1:n_k_points_task), &
                            1, nstates, vexx)

   ! ! Print EXX results
   ! do i_spin = 1, nspins
   !    write(info_str,'(2X,A,I5)') "Spin channel ", i_spin
   !    if (myid == 0) write(*,'(A)') info_str
   !    call mpi_barrier(MPI_COMM_WORLD, ierr)
   !    i_k_point_task = 0
   !    do i_k_point = 1, nkpts
   !       if (myid == mod(i_k_point-1, size) .and. myid <= nkpts) then
   !          write(*, '(2X,A,I5,3F13.5)') "K-point ", i_k_point, kpoints(:,i_k_point)
   !          write(*, '(2X,A5,A13)') "state", "vexx [Ha]"
   !          i_k_point_task = i_k_point_task + 1
   !          do i_state = 1, nstates
   !             write(*, '(2X,I5,1F13.5)') i_state, vexx(i_state, i_k_point_task, i_spin)
   !          end do
   !       end if
   !       call mpi_barrier(MPI_COMM_WORLD, ierr)
   !    end do
   ! end do

   call h%destroy()

   call finalize(.true.)

contains

   subroutine initialize
      implicit none
      integer :: provided
      call mpi_init_thread(MPI_THREAD_MULTIPLE, provided, ierr)
      if (MPI_THREAD_MULTIPLE /= provided) then
         write(*,*) "Warning: MPI_Init_thread provide ", provided, " != required", MPI_THREAD_MULTIPLE
      endif
      call librpa_init_global(.false., "output.txt", .true.)

      call mpi_comm_rank(MPI_COMM_WORLD, myid, ierr)
      call mpi_comm_size(MPI_COMM_WORLD, size, ierr)
   end subroutine initialize

   subroutine finalize(success)
      logical, intent(in) :: success

      if (success) then
         write(*,*) prog, " succeeded"
      else
         write(*,*) prog, " failed"
      end if

      call librpa_finalize_global
      call MPI_Finalize(ierr)
   end subroutine finalize

