      allocate(wg(nstates, nkpts, nspins), ekb(nstates, nkpts, nspins))
      wg(:, :, :) = 0.0_dp
      wg(1:2, :, :) = 2.0_dp
      ekb(:, :, :) = reshape([ &
         -0.626245559348763803_dp, -0.549248421709219947_dp, 0.795715865718289783_dp, 0.795715870153016036_dp, &
         0.795715870153017368_dp, 1.145199744905578850_dp, 1.145199750154672900_dp, 1.145199750154675340_dp, &
