         0.810843340998502415_dp, 0.810843340998505191_dp, 0.810843340998505968_dp, 0.810843340998506190_dp], shape(ekb))
   end subroutine initialize_wg_ekb

   subroutine finalize_wg_ekb()
      deallocate(wg, ekb)
   end subroutine finalize_wg_ekb

